from bakery import assert_equal

def summate(values: list[int]) -> int:
    total = 0
    for value in values:
        total = total + value
    return total

def count(values: list[int]) -> int:
    total = 0
    for value in values:
        total = total + 1
    return total

from bakery import assert_equal

def remove_xs(values: list[str]) -> list[str]:
    result = []
    for value in values:
        if value != "x":
            result.append(value)
    return result

def map_strs_to_ints(values: list[str]) -> list[int]:
    result = []
    for value in values:
        result.append(int(value))
    return result

def summate(values: list[int]) -> int:
